using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Update namespace according to your project
using YourNamespace.Data; // Update namespace according to your project

public class ProductController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductController()
    {
        _context = new ApplicationDbContext();
    }

    public ActionResult Details(int id)
    {
        var product = _context.Products.Find(id);
        var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();
        
        var viewModel = new ProductDetailsViewModel
        {
            Product = product,
            Reviews = reviews
        };

        return View(viewModel);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult SubmitReview(int productId, string content, string userName)
    {
        if (ModelState.IsValid)
        {
            var review = new Review
            {
                ProductId = productId,
                Content = content,
                UserName = userName,
                SubmissionDate = DateTime.Now
            };

            _context.Reviews.Add(review);
            _context.SaveChanges();
            return RedirectToAction("Details", new { id = productId });
        }

        return RedirectToAction("Details", new { id = productId });
    }
}

public class ProductDetailsViewModel
{
    public Product Product { get; set; }
    public List<Review> Reviews { get; set; }
}

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Content { get; set; }
    public string UserName { get; set; }
    public DateTime SubmissionDate { get; set; }
}

@model YourNamespace.Models.ProductDetailsViewModel

<h2>@Model.Product.Name</h2>
<p>@Html.DisplayFor(m => Model.Product.Description)</p>

<h3>Reviews</h3>
@foreach (var review in Model.Reviews)
{
    <div class="review">
        <strong>@review.UserName</strong> - <em>@review.SubmissionDate.ToShortDateString()</em>
        <div>@Html.Raw(review.Content)</div>
    </div>
}

<form asp-action="SubmitReview" method="post">
    @Html.Hidden("productId", Model.Product.Id)
    <div>
        <label for="userName">Name:</label>
        <input type="text" name="userName" required />
    </div>
    <div>
        <label for="content">Review:</label>
        <textarea name="content" required></textarea>
    </div>
    <button type="submit">Submit Review</button>
</form>